The following Python merge sort implementation contains a bug that causes incorrect sorting for arrays with duplicate elements. Identify the bug, explain its root cause, and provide the corrected function.

def merge_sort(arr):
    if len(arr) <= 1:
        return arr
    mid = len(arr) // 2
    left = merge_sort(arr[:mid])
    right = merge_sort(arr[mid:])
    return merge(left, right)

def merge(l, r):
    result = []
    i = j = 0
    while i < len(l) and j < len(r):
        if l[i] < r[j]:  # BUG: should be <=
            result.append(l[i]); i += 1
        else:
            result.append(r[j]); j += 1
    result += l[i:]
    result += r[j:]
    return result

The following binary search has an off-by-one error causing infinite loops. Identify and fix the bug. Explain why the original condition is wrong.

def binary_search(arr, target):
    lo, hi = 0, len(arr)
    while lo < hi:
        mid = (lo + hi) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            lo = mid  # BUG
        else:
            hi = mid
    return -1

